import React, { useState } from 'react';
import { Link } from 'react-router-dom';

import { Home, Heart, MessageSquare, Briefcase, MapPin } from 'lucide-react';

const BentoFeatures = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isOpen, setIsOpen] = useState({
    features: false,
    benefits: false,
    amenities: false,
  });

  const featureTabs = [
    { id: 'home', icon: <Home size={24} />, title: 'Home' },
    { id: 'benefits', icon: <Briefcase size={24} />, title: 'Benefits' },
    { id: 'amenities', icon: <MapPin size={24} />, title: 'Amenities' },
  ];

  const handleTabClick = (id) => {
    setActiveTab(id);
    setIsOpen((prevIsOpen) => ({ ...prevIsOpen, features: false, benefits: false, amenities: false }));
    setIsOpen((prevIsOpen) => ({ ...prevIsOpen, [id]: true }));
  };

  return (
    <div className="max-w-7xl mx-auto p-6 pt-8 md:p-8 lg:p-12 xl:p-16 2xl:p-20">
      <div className="flex flex-col md:flex-row items-center justify-between mb-8">
        <h2 className="text-3xl font-bold text-white">Luxuria Bento Features</h2>
        <button className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-2 px-4 rounded-md">
          <Link to="/bento#features">Explore Features</Link>
        </button>
      </div>

      <div className="flex flex-col md:flex-row md:justify-between items-center mb-16">
        <div className="flex flex-col md:flex-row md:items-center mb-4 md:mb-0">
          <div className="flex items-center justify-center md:bg-white md:rounded-md md:shadow-md md:p-4 md:w-40 md:h-40 md:flex-shrink-0">
            <Heart size={24} className="text-red-500" />
          </div>
          <div className="flex flex-col md:ml-4 md:items-start">
            <h3 className="text-lg font-bold text-white">Comforting Home</h3>
            <p className="text-gray-500">
              Enjoy the comforts of home in our Luxuria Bento features, designed for relaxation and rejuvenation.
            </p>
          </div>
        </div>

        <div className="flex flex-col md:flex-row md:items-center mb-4 md:mb-0">
          <div className="flex items-center justify-center md:bg-white md:rounded-md md:shadow-md md:p-4 md:w-40 md:h-40 md:flex-shrink-0">
            <MessageSquare size={24} className="text-green-500" />
          </div>
          <div className="flex flex-col md:ml-4 md:items-start">
            <h3 className="text-lg font-bold text-white">Personalized Service</h3>
            <p className="text-gray-500">
              Our dedicated team is committed to providing exceptional service and making your stay truly unforgettable.
            </p>
          </div>
        </div>

        <div className="flex flex-col md:flex-row md:items-center mb-4 md:mb-0">
          <div className="flex items-center justify-center md:bg-white md:rounded-md md:shadow-md md:p-4 md:w-40 md:h-40 md:flex-shrink-0">
            <Briefcase size={24} className="text-blue-500" />
          </div>
          <div className="flex flex-col md:ml-4 md:items-start">
            <h3 className="text-lg font-bold text-white">Luxurious Amenities</h3>
            <p className="text-gray-500">
              Indulge in our range of luxurious amenities, designed to make your stay with us truly unforgettable.
            </p>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-md shadow-md p-4 mb-16">
        <h3 className="text-lg font-bold text-gray-800">Key Features</h3>
        <div className="flex flex-col lg:flex-row items-start justify-between">
          {featureTabs.map((tab) => (
            <div
              key={tab.id}
              className={`flex items-center justify-center rounded-md p-4 mb-4 lg:mb-0 lg:mr-4 hover:bg-gray-100 cursor-pointer ${
                activeTab === tab.id ? 'bg-gray-100' : ''
              }`}
              onClick={() => handleTabClick(tab.id)}
            >
              {tab.icon}
              <span className="ml-2 text-lg font-bold text-gray-800">{tab.title}</span>
            </div>
          ))}
        </div>
      </div>

      <div className="flex flex-col lg:flex-row items-start justify-between mb-16">
        <div
          className={`flex flex-col lg:flex-row lg:items-center lg:justify-between mb-4 lg:mb-0 lg:mr-4 transition duration-300 ease-in-out ${
            isOpen.features ? 'h-64' : 'h-0'
          }`}
        >
          <h3 className="text-lg font-bold text-white">Feature 1</h3>
          <p className="text-gray-500">
            Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.
          </p>
        </div>

        <div
          className={`flex flex-col lg:flex-row lg:items-center lg:justify-between mb-4 lg:mb-0 lg:mr-4 transition duration-300 ease-in-out ${
            isOpen.benefits ? 'h-64' : 'h-0'
